tasks.description:
在 createNPC 函数之后、createTree 函数之前，添加 moveNPCToWork(npc) 函数：
function moveNPCToWork(npc) {
  if (!npc.userData.workTarget) return;
  const t = npc.userData.workTarget;
  const dx = t.x - npc.position.x;
  const dz = t.z - npc.position.z;
  const dist = Math.sqrt(dx*dx + dz*dz);
  if (dist > 0.1) {
    npc.position.x += dx * 0.02;
    npc.position.z += dz * 0.02;
    // 面向移动方向
    npc.rotation.y = Math.atan2(dx, dz);
  }
}
